-- ── RPC functions used directly by the frontend ─────────────────────────────

CREATE OR REPLACE FUNCTION public.create_employee_full(
  p_name text, p_email text, p_phone_no text DEFAULT NULL, p_department text DEFAULT NULL,
  p_role text DEFAULT 'Executive', p_branch text DEFAULT NULL, p_reporting_to_id uuid DEFAULT NULL
)
 RETURNS uuid
 LANGUAGE plpgsql SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_user_id   UUID;
  v_pass      TEXT;
BEGIN
  IF auth_role() NOT IN ('managing_director', 'executive_assistant', 'hr') THEN
    RAISE EXCEPTION 'Not authorized to create employees';
  END IF;

  v_pass := COALESCE(NULLIF(TRIM(p_phone_no), ''), 'ChangeMe123!');

  INSERT INTO auth.users (
    id, instance_id, email, encrypted_password,
    email_confirmed_at, raw_app_meta_data, raw_user_meta_data,
    created_at, updated_at, role, aud,
    confirmation_token, recovery_token, email_change_token_new, email_change
  ) VALUES (
    gen_random_uuid(),
    '00000000-0000-0000-0000-000000000000',
    p_email,
    extensions.crypt(v_pass, extensions.gen_salt('bf')),
    NOW(),
    '{"provider":"email","providers":["email"]}'::jsonb,
    jsonb_build_object('full_name', p_name),
    NOW(), NOW(),
    'authenticated', 'authenticated',
    '', '', '', ''
  )
  RETURNING id INTO v_user_id;

  INSERT INTO auth.identities (
    id, user_id, provider_id, provider, identity_data,
    last_sign_in_at, created_at, updated_at
  ) VALUES (
    gen_random_uuid(), v_user_id, v_user_id, 'email',
    jsonb_build_object('sub', v_user_id::text, 'email', p_email),
    NOW(), NOW(), NOW()
  );

  UPDATE profiles SET
    email      = p_email,
    full_name  = p_name,
    phone_no   = p_phone_no,
    role       = CASE p_role
                   WHEN 'MD'       THEN 'managing_director'
                   WHEN 'Director' THEN 'director'
                   WHEN 'EA'       THEN 'executive_assistant'
                   WHEN 'HR'       THEN 'hr'
                   WHEN 'Manager'  THEN 'manager'
                   ELSE                 'executive'
                 END::user_role,
    branch     = p_branch,
    manager_id = p_reporting_to_id
  WHERE id = v_user_id;

  INSERT INTO profiles (id, email, full_name, phone_no, role, branch, manager_id)
  SELECT v_user_id, p_email, p_name, p_phone_no,
    CASE p_role
      WHEN 'MD'       THEN 'managing_director'
      WHEN 'Director' THEN 'director'
      WHEN 'EA'       THEN 'executive_assistant'
      WHEN 'HR'       THEN 'hr'
      WHEN 'Manager'  THEN 'manager'
      ELSE                 'executive'
    END::user_role,
    p_branch, p_reporting_to_id
  WHERE NOT EXISTS (SELECT 1 FROM profiles WHERE id = v_user_id);

  RETURN v_user_id;
END;
$function$;
REVOKE EXECUTE ON FUNCTION public.create_employee_full(text, text, text, text, text, text, uuid) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.create_employee_full(text, text, text, text, text, text, uuid) TO authenticated;

CREATE OR REPLACE FUNCTION public.delete_employee(p_employee_id uuid)
 RETURNS void
 LANGUAGE plpgsql SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM profiles
    WHERE id = auth.uid()
    AND role IN ('managing_director', 'director', 'executive_assistant')
  ) THEN
    RAISE EXCEPTION 'Insufficient permissions to delete employees.';
  END IF;

  IF p_employee_id = auth.uid() THEN
    RAISE EXCEPTION 'You cannot delete your own account.';
  END IF;

  DELETE FROM auth.users WHERE id = p_employee_id;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_employee_jd_report(p_employee_id uuid, p_start timestamptz, p_end timestamptz)
 RETURNS TABLE(id text, work_details text, monthly_target numeric, achieved_in_period numeric, status text)
 LANGUAGE plpgsql SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT can_view_employee(p_employee_id) THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    jd.id::TEXT,
    jd.work_details,
    jd.monthly_target::NUMERIC,
    COALESCE(agg.total, 0)::NUMERIC AS achieved_in_period,
    jd.status
  FROM job_directions jd
  LEFT JOIN (
    SELECT job_direction_id, SUM(amount_completed) AS total
    FROM job_direction_progress_logs
    WHERE employee_id = p_employee_id
      AND created_at >= p_start
      AND created_at <  p_end
    GROUP BY job_direction_id
  ) agg ON agg.job_direction_id = jd.id
  WHERE jd.employee_id = p_employee_id
  ORDER BY jd.work_details;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_employee_task_report(p_employee_id uuid, p_start timestamptz, p_end timestamptz)
 RETURNS TABLE(id text, task_name text, due_date date, status text, created_at timestamptz, completed_at timestamptz)
 LANGUAGE plpgsql SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT can_view_employee(p_employee_id) THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    st.id::TEXT,
    st.task_name,
    st.due_date,
    st.status,
    st.created_at,
    st.completed_at
  FROM special_tasks st
  JOIN task_assignees ta ON ta.task_id = st.id AND ta.employee_id = p_employee_id
  WHERE st.created_at >= p_start OR st.due_date >= p_start::DATE
  ORDER BY st.due_date DESC NULLS LAST, st.created_at DESC;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_employee_team_task_report(p_employee_id uuid, p_start timestamptz, p_end timestamptz)
 RETURNS TABLE(id uuid, sub_task_title text, job_title text, task_type text, due_date date, status text, completed_at timestamptz, notes text, created_at timestamptz)
 LANGUAGE plpgsql SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT can_view_employee(p_employee_id) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;

  RETURN QUERY
  SELECT
    t.id,
    t.title       AS sub_task_title,
    j.title       AS job_title,
    t.task_type,
    t.due_date,
    t.status::TEXT,
    t.completed_at,
    t.notes,
    t.created_at
  FROM  team_job_tasks t
  JOIN  team_jobs       j ON j.id = t.job_id
  WHERE t.assignee_id = p_employee_id
    AND t.created_at BETWEEN p_start AND p_end
  ORDER BY t.created_at DESC;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_jd_monthly_history(p_year integer, p_month integer)
 RETURNS TABLE(id text, work_details text, monthly_target numeric, monthly_achieved numeric, employee_id uuid, employee_name text, status text)
 LANGUAGE plpgsql SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_id   UUID := auth.uid();
  v_caller_role TEXT;
  v_start       TIMESTAMPTZ;
  v_end         TIMESTAMPTZ;
BEGIN
  SELECT role INTO v_caller_role FROM profiles WHERE id = v_caller_id;

  v_start := make_timestamptz(p_year, p_month, 1, 0, 0, 0, 'UTC');
  v_end   := v_start + INTERVAL '1 month';

  RETURN QUERY
  SELECT
    jd.id::TEXT,
    jd.work_details,
    jd.monthly_target,
    COALESCE(agg.total, 0)::NUMERIC AS monthly_achieved,
    jd.employee_id,
    p.full_name AS employee_name,
    jd.status
  FROM job_directions jd
  JOIN profiles p ON p.id = jd.employee_id
  LEFT JOIN (
    SELECT job_direction_id, SUM(amount_completed) AS total
    FROM job_direction_progress_logs
    WHERE created_at >= v_start AND created_at < v_end
    GROUP BY job_direction_id
  ) agg ON agg.job_direction_id = jd.id
  WHERE
    CASE
      WHEN v_caller_role IN ('managing_director', 'executive_assistant', 'hr', 'director')
        THEN TRUE
      WHEN v_caller_role = 'manager'
        THEN (jd.employee_id = v_caller_id OR jd.manager_id = v_caller_id)
      ELSE
        jd.employee_id = v_caller_id
    END
  ORDER BY p.full_name, jd.work_details;
END;
$function$;

-- ── View ────────────────────────────────────────────────────────────────────
-- security_invoker = true is required: without it, this view runs as its
-- owner and RLS on the underlying tables is never evaluated for the querying
-- user (see live-DB security fix applied 2026-07-01).
CREATE OR REPLACE VIEW public.job_directions_with_progress AS
SELECT
  jd.id,
  jd.work_details,
  jd.description,
  jd.expected_output,
  jd.expected_output_achieved,
  jd.employee_id,
  jd.manager_id,
  jd.department_id,
  jd.status,
  jd.remarks,
  jd.daily_target,
  jd.weekly_target,
  jd.monthly_target,
  COALESCE(daily.amount, 0::numeric) AS daily_completed,
  COALESCE(weekly.amount, 0::numeric) AS weekly_completed,
  COALESCE(monthly.amount, 0::numeric) AS monthly_completed
FROM job_directions jd
LEFT JOIN (
  SELECT job_direction_progress_logs.job_direction_id,
         sum(job_direction_progress_logs.amount_completed) AS amount
  FROM job_direction_progress_logs
  WHERE job_direction_progress_logs.created_at::date = CURRENT_DATE
  GROUP BY job_direction_progress_logs.job_direction_id
) daily ON daily.job_direction_id = jd.id
LEFT JOIN (
  SELECT job_direction_progress_logs.job_direction_id,
         sum(job_direction_progress_logs.amount_completed) AS amount
  FROM job_direction_progress_logs
  WHERE job_direction_progress_logs.created_at >= date_trunc('week', CURRENT_DATE::timestamp)
  GROUP BY job_direction_progress_logs.job_direction_id
) weekly ON weekly.job_direction_id = jd.id
LEFT JOIN (
  SELECT job_direction_progress_logs.job_direction_id,
         sum(job_direction_progress_logs.amount_completed) AS amount
  FROM job_direction_progress_logs
  WHERE job_direction_progress_logs.created_at >= date_trunc('month', CURRENT_DATE::timestamp)
  GROUP BY job_direction_progress_logs.job_direction_id
) monthly ON monthly.job_direction_id = jd.id;

ALTER VIEW public.job_directions_with_progress SET (security_invoker = true);

