-- departments
DROP POLICY IF EXISTS "departments_read_all" ON public.departments;
CREATE POLICY "departments_read_all" ON public.departments FOR SELECT USING (true);
DROP POLICY IF EXISTS "departments_admin_write" ON public.departments;
CREATE POLICY "departments_admin_write" ON public.departments FOR ALL USING (
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = ANY (ARRAY['managing_director'::user_role, 'executive_assistant'::user_role]))
);

-- profiles
DROP POLICY IF EXISTS "profiles: all active read all active" ON public.profiles;
CREATE POLICY "profiles: all active read all active" ON public.profiles FOR SELECT USING (auth.uid() IS NOT NULL);
DROP POLICY IF EXISTS "profiles: self read" ON public.profiles;
CREATE POLICY "profiles: self read" ON public.profiles FOR SELECT USING (id = auth.uid());
DROP POLICY IF EXISTS "profiles: manager read reports" ON public.profiles;
CREATE POLICY "profiles: manager read reports" ON public.profiles FOR SELECT USING (manager_id = auth.uid());
DROP POLICY IF EXISTS "profiles: executive read all" ON public.profiles;
CREATE POLICY "profiles: executive read all" ON public.profiles FOR SELECT USING ((auth_role())::text = ANY (ARRAY['managing_director'::text, 'executive_assistant'::text, 'hr'::text]));
DROP POLICY IF EXISTS "profiles: dept head read dept" ON public.profiles;
CREATE POLICY "profiles: dept head read dept" ON public.profiles FOR SELECT USING (
  department_id = auth_dept_id() AND (auth_role())::text = ANY (ARRAY['director'::text, 'managing_director'::text, 'executive_assistant'::text, 'hr'::text])
);
DROP POLICY IF EXISTS "profiles: self update" ON public.profiles;
CREATE POLICY "profiles: self update" ON public.profiles FOR UPDATE USING (id = auth.uid()) WITH CHECK (id = auth.uid());
DROP POLICY IF EXISTS "profiles: admin update any" ON public.profiles;
CREATE POLICY "profiles: admin update any" ON public.profiles FOR UPDATE
  USING ((auth_role())::text = ANY (ARRAY['managing_director'::text, 'executive_assistant'::text, 'hr'::text, 'director'::text]))
  WITH CHECK ((auth_role())::text = ANY (ARRAY['managing_director'::text, 'executive_assistant'::text, 'hr'::text, 'director'::text]));

-- notifications
DROP POLICY IF EXISTS "notifications: own only" ON public.notifications;
CREATE POLICY "notifications: own only" ON public.notifications FOR ALL USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());

-- job_directions
DROP POLICY IF EXISTS "job_directions: select scope" ON public.job_directions;
CREATE POLICY "job_directions: select scope" ON public.job_directions FOR SELECT USING (
  employee_id = auth.uid() OR manager_id = auth.uid() OR auth_role() = ANY (ARRAY['director'::user_role, 'managing_director'::user_role])
);
DROP POLICY IF EXISTS "job_directions: admin read all" ON public.job_directions;
CREATE POLICY "job_directions: admin read all" ON public.job_directions FOR SELECT USING (
  (auth_role())::text = ANY (ARRAY['managing_director'::text, 'executive_assistant'::text, 'hr'::text])
);
DROP POLICY IF EXISTS "job_directions: insert scope" ON public.job_directions;
CREATE POLICY "job_directions: insert scope" ON public.job_directions FOR INSERT WITH CHECK (
  employee_id = auth.uid() OR manager_id = auth.uid() OR auth_role() = ANY (ARRAY['director'::user_role, 'managing_director'::user_role])
);
DROP POLICY IF EXISTS "job_directions: update scope" ON public.job_directions;
CREATE POLICY "job_directions: update scope" ON public.job_directions FOR UPDATE USING (
  employee_id = auth.uid() OR manager_id = auth.uid() OR auth_role() = ANY (ARRAY['director'::user_role, 'managing_director'::user_role])
);
DROP POLICY IF EXISTS "job_directions: delete scope" ON public.job_directions;
CREATE POLICY "job_directions: delete scope" ON public.job_directions FOR DELETE USING (
  manager_id = auth.uid() OR (employee_id = auth.uid() AND status = 'draft'::text) OR
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = ANY (ARRAY['director'::user_role, 'managing_director'::user_role, 'executive_assistant'::user_role, 'hr'::user_role]))
);

-- job_direction_progress_logs
DROP POLICY IF EXISTS "Employees can read their own logs" ON public.job_direction_progress_logs;
CREATE POLICY "Employees can read their own logs" ON public.job_direction_progress_logs FOR SELECT USING (auth.uid() = employee_id);
DROP POLICY IF EXISTS "Employees can insert their own logs" ON public.job_direction_progress_logs;
CREATE POLICY "Employees can insert their own logs" ON public.job_direction_progress_logs FOR INSERT WITH CHECK (auth.uid() = employee_id);
DROP POLICY IF EXISTS "Managers can read team logs" ON public.job_direction_progress_logs;
CREATE POLICY "Managers can read team logs" ON public.job_direction_progress_logs FOR SELECT USING (
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = job_direction_progress_logs.employee_id AND profiles.manager_id = auth.uid())
);
DROP POLICY IF EXISTS "Directors/MDs can read all logs" ON public.job_direction_progress_logs;
CREATE POLICY "Directors/MDs can read all logs" ON public.job_direction_progress_logs FOR SELECT USING (
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = ANY (ARRAY['director'::user_role, 'managing_director'::user_role, 'executive_assistant'::user_role]))
);

-- special_tasks
DROP POLICY IF EXISTS "special_tasks: select scope" ON public.special_tasks;
CREATE POLICY "special_tasks: select scope" ON public.special_tasks FOR SELECT USING (
  assigned_by = auth.uid() OR is_task_assignee(id, auth.uid()) OR auth_role() = ANY (ARRAY['director'::user_role, 'managing_director'::user_role])
);
DROP POLICY IF EXISTS "special_tasks: admin read all" ON public.special_tasks;
CREATE POLICY "special_tasks: admin read all" ON public.special_tasks FOR SELECT USING (
  (auth_role())::text = ANY (ARRAY['managing_director'::text, 'executive_assistant'::text, 'hr'::text])
);
DROP POLICY IF EXISTS "special_tasks: manager full" ON public.special_tasks;
CREATE POLICY "special_tasks: manager full" ON public.special_tasks FOR ALL USING (
  assigned_by = auth.uid() OR auth_role() = ANY (ARRAY['director'::user_role, 'managing_director'::user_role])
);
DROP POLICY IF EXISTS "special_tasks: assignee update status" ON public.special_tasks;
CREATE POLICY "special_tasks: assignee update status" ON public.special_tasks FOR UPDATE
  USING (is_task_assignee(id, auth.uid())) WITH CHECK (is_task_assignee(id, auth.uid()));

-- task_assignees
DROP POLICY IF EXISTS "task_assignees: select" ON public.task_assignees;
CREATE POLICY "task_assignees: select" ON public.task_assignees FOR SELECT USING (
  employee_id = auth.uid() OR is_task_creator(task_id, auth.uid()) OR auth_role() = ANY (ARRAY['director'::user_role, 'managing_director'::user_role])
