);
DROP POLICY IF EXISTS "MD, Director and EA can update reporting" ON public.reporting;
CREATE POLICY "MD, Director and EA can update reporting" ON public.reporting FOR UPDATE USING (
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = ANY (ARRAY['managing_director'::user_role, 'director'::user_role, 'executive_assistant'::user_role]))
);
DROP POLICY IF EXISTS "MD, Director and EA can delete reporting" ON public.reporting;
CREATE POLICY "MD, Director and EA can delete reporting" ON public.reporting FOR DELETE USING (
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = ANY (ARRAY['managing_director'::user_role, 'director'::user_role, 'executive_assistant'::user_role]))
);

-- role_permissions
DROP POLICY IF EXISTS "role_permissions: public read" ON public.role_permissions;
CREATE POLICY "role_permissions: public read" ON public.role_permissions FOR SELECT USING (auth.uid() IS NOT NULL);
DROP POLICY IF EXISTS "role_permissions: admin update" ON public.role_permissions;
CREATE POLICY "role_permissions: admin update" ON public.role_permissions FOR UPDATE
