  created_by = auth.uid() OR (SELECT profiles.role FROM profiles WHERE profiles.id = auth.uid()) = ANY (ARRAY['managing_director'::user_role, 'executive_assistant'::user_role, 'hr'::user_role])
);

-- team_job_tasks
DROP POLICY IF EXISTS "team_job_tasks_select" ON public.team_job_tasks;
CREATE POLICY "team_job_tasks_select" ON public.team_job_tasks FOR SELECT TO authenticated USING (
  is_team_job_member(job_id) OR (SELECT profiles.role FROM profiles WHERE profiles.id = auth.uid()) = ANY (ARRAY['managing_director'::user_role, 'executive_assistant'::user_role, 'hr'::user_role, 'director'::user_role])
);
DROP POLICY IF EXISTS "team_job_tasks_insert" ON public.team_job_tasks;
CREATE POLICY "team_job_tasks_insert" ON public.team_job_tasks FOR INSERT TO authenticated WITH CHECK (
  EXISTS (SELECT 1 FROM team_jobs WHERE team_jobs.id = team_job_tasks.job_id AND (team_jobs.created_by = auth.uid() OR team_jobs.head_id = auth.uid()))
  OR (SELECT profiles.role FROM profiles WHERE profiles.id = auth.uid()) = ANY (ARRAY['managing_director'::user_role, 'executive_assistant'::user_role, 'hr'::user_role])
);
DROP POLICY IF EXISTS "team_job_tasks_update" ON public.team_job_tasks;
CREATE POLICY "team_job_tasks_update" ON public.team_job_tasks FOR UPDATE TO authenticated USING (
  assignee_id = auth.uid()
  OR EXISTS (SELECT 1 FROM team_jobs WHERE team_jobs.id = team_job_tasks.job_id AND (team_jobs.created_by = auth.uid() OR team_jobs.head_id = auth.uid()))
  OR (SELECT profiles.role FROM profiles WHERE profiles.id = auth.uid()) = ANY (ARRAY['managing_director'::user_role, 'executive_assistant'::user_role, 'hr'::user_role])
);
DROP POLICY IF EXISTS "team_job_tasks_delete" ON public.team_job_tasks;
CREATE POLICY "team_job_tasks_delete" ON public.team_job_tasks FOR DELETE TO authenticated USING (
  EXISTS (SELECT 1 FROM team_jobs WHERE team_jobs.id = team_job_tasks.job_id AND (team_jobs.created_by = auth.uid() OR team_jobs.head_id = auth.uid()))
  OR (SELECT profiles.role FROM profiles WHERE profiles.id = auth.uid()) = ANY (ARRAY['managing_director'::user_role, 'executive_assistant'::user_role, 'hr'::user_role])
);

-- capacity_plans
DROP POLICY IF EXISTS "capacity_plans_read" ON public.capacity_plans;
CREATE POLICY "capacity_plans_read" ON public.capacity_plans FOR SELECT USING (auth.role() = 'authenticated'::text);
DROP POLICY IF EXISTS "capacity_plans_write_admin" ON public.capacity_plans;
CREATE POLICY "capacity_plans_write_admin" ON public.capacity_plans FOR ALL USING (
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = ANY (ARRAY['managing_director'::user_role, 'executive_assistant'::user_role, 'hr'::user_role]))
);
DROP POLICY IF EXISTS "capacity_plans_write_director" ON public.capacity_plans;
CREATE POLICY "capacity_plans_write_director" ON public.capacity_plans FOR ALL USING (
  EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = 'director'::user_role AND profiles.branch = capacity_plans.branch)
);

-- ── Auth trigger (profile auto-creation on signup) ──────────────────────────
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();
